// src/Menu.js
import React from 'react';
import './Menu.css';

const rawMenu = [
    { id: 62, name: 'Jupiler',            brand: 'Anheuser-Busch InBev', category: 'Beer',        subcat: 'Lager',       price: 3.00, created_at: '2025-05-19 18:00:00' },
    { id: 63, name: 'Stella Artois',      brand: 'Anheuser-Busch InBev', category: 'Beer',        subcat: 'Lager',       price: 3.00, created_at: '2025-05-19 18:00:00' },
    { id: 64, name: 'Corona Extra',       brand: 'Grupo Modelo',         category: 'Beer',        subcat: 'Lager',       price: 3.50, created_at: '2025-05-19 18:00:00' },
    { id: 65, name: 'Palm',               brand: 'Brouwerij Palm',      category: 'Beer',        subcat: 'Lager',       price: 2.75, created_at: '2025-05-19 18:00:00' },
    { id: 66, name: 'Cola',               brand: 'Coca-Cola',            category: 'Soft Drinks', subcat: 'Cola',        price: 2.50, created_at: '2025-05-19 18:00:00' },
    { id: 67, name: 'Sprite',             brand: 'Coca-Cola',            category: 'Soft Drinks', subcat: 'Soda Water',  price: 2.50, created_at: '2025-05-19 18:00:00' },
    { id: 68, name: 'Fanta Orange',       brand: 'Coca-Cola',            category: 'Soft Drinks', subcat: 'Lemonade',    price: 2.50, created_at: '2025-05-19 18:00:00' },
    { id: 69, name: '7Up',                brand: 'Dr Pepper Snapple',    category: 'Soft Drinks', subcat: 'Soda Water',  price: 2.50, created_at: '2025-05-19 18:00:00' },
    { id: 70, name: 'Homemade Lemonade',  brand: 'House Recipe',         category: 'Soft Drinks', subcat: 'Lemonade',    price: 3.00, created_at: '2025-05-19 18:00:00' },
    { id: 71, name: 'Homemade Orange Soda',brand: 'House Recipe',        category: 'Soft Drinks', subcat: '',            price: 3.00, created_at: '2025-05-19 18:00:00' },
    { id: 72, name: 'Orange Juice',       brand: 'Tropicana',            category: 'Juices',      subcat: 'Orange',      price: 3.50, created_at: '2025-05-19 18:00:00' },
    { id: 73, name: 'Apple Juice',        brand: 'Innocent',             category: 'Juices',      subcat: 'Apple',       price: 3.50, created_at: '2025-05-19 18:00:00' },
    { id: 74, name: 'Berry Blast',        brand: 'House Recipe',         category: 'Juices',      subcat: 'Mixed Fruit', price: 4.00, created_at: '2025-05-19 18:00:00' },
    { id: 75, name: 'Espresso',           brand: 'House Recipe',         category: 'Coffee',      subcat: 'Espresso',    price: 2.50, created_at: '2025-05-19 18:00:00' },
    { id: 76, name: 'Latte',              brand: 'House Recipe',         category: 'Coffee',      subcat: 'Latte',       price: 3.00, created_at: '2025-05-19 18:00:00' },
    { id: 77, name: 'Cappuccino',         brand: 'House Recipe',         category: 'Coffee',      subcat: 'Cappuccino',  price: 3.00, created_at: '2025-05-19 18:00:00' },
    { id: 78, name: 'Virgin Mary',        brand: 'House Recipe',         category: 'Mocktails',   subcat: '',            price: 4.50, created_at: '2025-05-19 18:00:00' },
    { id: 79, name: 'Virgin Mojito',      brand: 'Tropical Twist',       category: 'Mocktails',   subcat: '',            price: 4.50, created_at: '2025-05-19 18:00:00' },
];

const Menu = () => {
    // groepeer per category
    const grouped = rawMenu.reduce((acc, item) => {
        if (!acc[item.category]) acc[item.category] = [];
        acc[item.category].push(item);
        return acc;
    }, {});

    return (
        <div className="menu-container">
            <h2>Your menu</h2>
            {Object.entries(grouped).map(([category, items]) => (
                <section key={category} className="menu-section">
                    <h3 className="menu-category">{category}</h3>
                    <ul className="menu-list">
                        {items.map(i => (
                            <li key={i.id} className="menu-item">
                                <div className="item-name">{i.name}</div>
                                <div className="item-brand">{i.brand}</div>
                                <div className="item-price">€{i.price.toFixed(2)}</div>
                            </li>
                        ))}
                    </ul>
                </section>
            ))}
        </div>
    );
};

export default Menu;
